import { nextTick } from 'vue';
import { initScrollAnimations } from '../utils/scrollAnimations';

export default {
  mounted() {
    nextTick(() => {
      this.__scrollCleanup = initScrollAnimations(this.$el);
    });
  },
  beforeUnmount() {
    if (this.__scrollCleanup) {
      this.__scrollCleanup();
      this.__scrollCleanup = null;
    }
  }
};
