<template>
  <div>
    <h1 data-scroll-reveal>
      Where I've Wandered
    </h1>
    <article data-scroll-group data-scroll-step="110">
      <p>A traveler at heart. I keep finding excuses to be somewhere new, then spend ages noticing the small things most people walk past. Here's a globe of the places that have stuck with me. Give it a spin, and tap a point to see where I stood.</p>

      <div class="globe-wrap" ref="wrap" data-scroll-pop="true">
        <div
          class="globe-stage"
          ref="stage"
          @pointerenter="onGlobeEnter"
          @pointerleave="onGlobeLeave"
        >
          <canvas ref="canvas" class="globe-canvas"></canvas>

          <div
            class="globe-tooltip"
            :class="{ 'is-visible': !!active }"
            :style="tipStyle"
            aria-hidden="true"
          >
            <div class="globe-tooltip-card" v-if="active">
              <img :src="active.img" :alt="active.label" class="globe-tooltip-img">
              <div class="globe-tooltip-text">
                <template v-if="active.local">
                  <span class="gt-local">{{ active.local }}</span>
                  <span class="gt-en">{{ active.label }}</span>
                </template>
                <span v-else class="gt-en gt-en-only">{{ active.label }}</span>
              </div>
            </div>
          </div>
        </div>

        <p class="globe-hint">Drag to spin · pinch to zoom · tap a point</p>
      </div>

      <p class="globe-places">
        <span
          v-for="(p, i) in places"
          :key="p.label"
          class="globe-chip"
          :class="{ 'is-active': active && active.en === p.en }"
          @click="focusPlace(i)"
        >{{ p.label }}</span>
      </p>
    </article>
  </div>
</template>

<script>
import scrollRevealMixin from '../mixins/scrollRevealMixin';
import { places, HOME } from '../data/places';

export default {
  name: 'JourneyTab',
  mixins: [scrollRevealMixin],
  data() {
    return {
      places,
      active: null,     // currently shown place (hover or selected)
      pinned: false,    // true when a place was tapped (sticks until tapping empty space)
      hoverIndex: null,
      pointerInsideGlobe: false,
      zoomLevel: 1,
      tipStyle: {},
      d3: null,
      land: null,
      graticule: null,
    };
  },
  async mounted() {
    // Load the globe libraries and world outline only on this route.
    const [{ geoOrthographic, geoPath, geoGraticule10, geoDistance }, topo] = await Promise.all([
      import('d3-geo'),
      import('topojson-client'),
    ]);
    const world = await fetch('/assets/data/land-110m.json').then(r => r.json());

    this.d3 = { geoPath, geoDistance };
    this.land = topo.feature(world, world.objects.land);
    this.graticule = geoGraticule10();

    this.rotation = [-HOME[0], -22];
    this.velocity = 0.16;               // idle spin, degrees per frame-ish
    this.lastInteract = 0;
    this.dragging = false;
    this.pinching = false;
    this.tween = null;
    this.screenPins = [];
    this.reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

    this.projection = geoOrthographic().clipAngle(90).precision(0.4);
    this.ctx = this.$refs.canvas.getContext('2d');

    this.resize();
    this._onResize = () => this.resize();
    window.addEventListener('resize', this._onResize);

    const cv = this.$refs.canvas;
    cv.addEventListener('pointerdown', this.onDown);
    cv.addEventListener('wheel', this.onWheel, { passive: false });
    cv.addEventListener('touchstart', this.onTouchStart, { passive: false });
    cv.addEventListener('touchmove', this.onTouchMove, { passive: false });
    cv.addEventListener('touchend', this.onTouchEnd);
    window.addEventListener('pointermove', this.onMove);
    window.addEventListener('pointerup', this.onUp);

    this.startTime = performance.now();
    this.loop = (t) => {
      this.tick(t);
      this._raf = requestAnimationFrame(this.loop);
    };
    this._raf = requestAnimationFrame(this.loop);
  },
  unmounted() {
    cancelAnimationFrame(this._raf);
    this.clearHoverState();
    window.removeEventListener('resize', this._onResize);
    window.removeEventListener('pointermove', this.onMove);
    window.removeEventListener('pointerup', this.onUp);
    const cv = this.$refs.canvas;
    if (cv) {
      cv.removeEventListener('pointerdown', this.onDown);
      cv.removeEventListener('wheel', this.onWheel);
      cv.removeEventListener('touchstart', this.onTouchStart);
      cv.removeEventListener('touchmove', this.onTouchMove);
      cv.removeEventListener('touchend', this.onTouchEnd);
    }
  },
  methods: {
    resize() {
      const wrap = this.$refs.wrap;
      if (!wrap) return;
      const size = Math.min(wrap.clientWidth, 560);
      const dpr = Math.min(window.devicePixelRatio || 1, 2);
      const cv = this.$refs.canvas;
      this.size = size;
      cv.width = size * dpr;
      cv.height = size * dpr;
      cv.style.width = size + 'px';
      cv.style.height = size + 'px';
      this.ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      this.baseScale = size / 2 - 6;
      this.projection
        .translate([size / 2, size / 2]);
      this.applyZoom();
    },
    applyZoom() {
      if (!this.projection || !this.baseScale) return;
      this.projection.scale(this.baseScale * this.zoomLevel);
    },
    palette() {
      const dark = document.body.classList.contains('dark-mode');
      return dark
        ? { ocean: 'rgba(255,255,255,0.02)', grat: 'rgba(255,255,255,0.08)',
            land: 'rgba(255,255,255,0.05)', coast: 'rgba(255,255,255,0.30)',
            outline: 'rgba(255,255,255,0.22)', pin: '#dcdcdc', active: '#ffffff',
            glow: '255,255,255' }
        : { ocean: 'rgba(0,0,0,0.015)', grat: 'rgba(0,0,0,0.07)',
            land: 'rgba(0,0,0,0.05)', coast: 'rgba(0,0,0,0.24)',
            outline: 'rgba(0,0,0,0.18)', pin: '#444444', active: '#000000',
            glow: '40,40,40' };
    },
    tick(t) {
      const dt = Math.min((t - (this._last || t)) / 16.67, 3);
      this._last = t;
      const now = t;

      // tween the camera toward a tapped place
      if (this.tween) {
        const k = 0.14 * dt;
        this.rotation[0] += this.shortest(this.tween[0] - this.rotation[0]) * k;
        this.rotation[1] += (this.tween[1] - this.rotation[1]) * k;
        if (Math.abs(this.shortest(this.tween[0] - this.rotation[0])) < 0.3 &&
            Math.abs(this.tween[1] - this.rotation[1]) < 0.3) {
          this.rotation[0] = this.tween[0];
          this.rotation[1] = this.tween[1];
          this.tween = null;
        }
      } else if (!this.shouldPauseSpin(now)) {
        // idle auto-spin
        this.rotation[0] += this.velocity * dt;
      }

      this.projection.rotate(this.rotation);
      this.render(now);
    },
    render(now) {
      const ctx = this.ctx;
      const c = this.palette();
      const path = this.d3.geoPath(this.projection, ctx);
      const s = this.size;
      ctx.clearRect(0, 0, s, s);

      ctx.beginPath(); path({ type: 'Sphere' }); ctx.fillStyle = c.ocean; ctx.fill();
      ctx.beginPath(); path(this.graticule); ctx.lineWidth = 0.5; ctx.strokeStyle = c.grat; ctx.stroke();
      ctx.beginPath(); path(this.land); ctx.fillStyle = c.land; ctx.fill();
      ctx.lineWidth = 0.6; ctx.strokeStyle = c.coast; ctx.stroke();
      ctx.beginPath(); path({ type: 'Sphere' }); ctx.lineWidth = 1; ctx.strokeStyle = c.outline; ctx.stroke();

      // pins on the near hemisphere
      const center = [-this.rotation[0], -this.rotation[1]];
      const pulse = 0.5 + 0.5 * Math.sin(now / 650);
      this.screenPins = [];
      this.places.forEach((p, i) => {
        if (this.d3.geoDistance(p.coord, center) > Math.PI / 2) return;
        const xy = this.projection(p.coord);
        if (!xy) return;
        const [x, y] = xy;
        const isActive = this.active && this.active.en === p.en;
        this.screenPins.push({ i, x, y });

        // soft pulsing halo
        const haloR = (isActive ? 11 : 8) + pulse * 3;
        ctx.beginPath();
        ctx.arc(x, y, haloR, 0, 2 * Math.PI);
        ctx.fillStyle = `rgba(${c.glow}, ${(isActive ? 0.16 : 0.10) * (1 - pulse * 0.5)})`;
        ctx.fill();

        // dot
        ctx.beginPath();
        ctx.arc(x, y, isActive ? 4.2 : 3, 0, 2 * Math.PI);
        ctx.fillStyle = isActive ? c.active : c.pin;
        ctx.fill();
        ctx.lineWidth = 1.4;
        ctx.strokeStyle = document.body.classList.contains('dark-mode') ? '#0d0d0d' : '#ffffff';
        ctx.stroke();
      });

      if (this.active) this.placeTooltip();
    },
    placeTooltip() {
      const hit = this.screenPins.find(sp => this.places[sp.i].en === this.active.en);
      if (!hit) { this.tipStyle = { opacity: 0 }; return; }
      this.tipStyle = {
        transform: `translate(${this.clampTooltipX(hit.x)}px, ${this.clampTooltipY(hit.y)}px)`,
      };
    },
    shouldPauseSpin(now) {
      return (
        this.dragging ||
        this.reduceMotion ||
        this.pointerInsideGlobe ||
        !!this.active ||
        (now - this.lastInteract) <= 2200
      );
    },
    clampTooltipX(x) {
      const width = 300;
      return Math.max(width / 2, Math.min(this.size - width / 2, x));
    },
    clampTooltipY(y) {
      return Math.max(172, y);
    },
    shortest(deg) {
      // normalize a longitude delta into [-180, 180] for the shortest spin
      let d = deg % 360;
      if (d > 180) d -= 360;
      if (d < -180) d += 360;
      return d;
    },
    hitTest(clientX, clientY) {
      const rect = this.$refs.canvas.getBoundingClientRect();
      const x = clientX - rect.left, y = clientY - rect.top;
      let best = null, bestD = 16; // px radius
      for (const sp of this.screenPins) {
        const d = Math.hypot(sp.x - x, sp.y - y);
        if (d < bestD) { bestD = d; best = sp; }
      }
      return best;
    },
    onGlobeEnter() {
      this.pointerInsideGlobe = true;
      this.lastInteract = performance.now();
    },
    onGlobeLeave() {
      this.pointerInsideGlobe = false;
      if (!this.pinned) {
        this.clearHoverState();
        this.active = null;
      }
    },
    clearHoverState() {
      this.hoverIndex = null;
    },
    showHoverPlace(index) {
      this.active = this.places[index];
      this.hoverIndex = index;
    },
    onWheel(e) {
      // Only a trackpad pinch zooms. macOS/Windows deliver a pinch as a wheel
      // event with ctrlKey set; a plain two-finger scroll has ctrlKey false and
      // is left untouched so it scrolls the page.
      if (!e.ctrlKey) return;
      e.preventDefault();
      this.lastInteract = performance.now();
      const factor = Math.exp(-e.deltaY * 0.01);
      this.zoomLevel = Math.max(0.8, Math.min(4.5, this.zoomLevel * factor));
      this.applyZoom();
    },
    onTouchStart(e) {
      if (e.touches.length === 2) {
        this.pinching = true;
        this.dragging = false;
        this._pinchDist = this.touchDist(e.touches);
      }
    },
    onTouchMove(e) {
      if (this.pinching && e.touches.length === 2) {
        e.preventDefault();
        const d = this.touchDist(e.touches);
        if (this._pinchDist > 0) {
          const factor = d / this._pinchDist;
          this.zoomLevel = Math.max(0.8, Math.min(4.5, this.zoomLevel * factor));
          this.applyZoom();
        }
        this._pinchDist = d;
        this.lastInteract = performance.now();
      }
    },
    onTouchEnd(e) {
      if (!e.touches || e.touches.length < 2) this.pinching = false;
    },
    touchDist(t) {
      return Math.hypot(t[0].clientX - t[1].clientX, t[0].clientY - t[1].clientY);
    },
    onDown(e) {
      this.dragging = true;
      this.moved = 0;
      this.lastInteract = performance.now();
      this.tween = null;
      this.clearHoverState();
      this._start = { x: e.clientX, y: e.clientY, rot: [...this.rotation] };
    },
    onMove(e) {
      if (this.pinching) return;
      if (this.dragging) {
        const dx = e.clientX - this._start.x;
        const dy = e.clientY - this._start.y;
        this.moved += Math.abs(dx) + Math.abs(dy);
        const k = 0.3; // degrees per pixel-ish, scaled by globe size
        this.rotation = [
          this._start.rot[0] + dx * k,
          Math.max(-88, Math.min(88, this._start.rot[1] - dy * k)),
        ];
        this.lastInteract = performance.now();
        return;
      }
      // hover highlight (skip while a place is pinned by tap)
      if (this.pinned) return;
      const hit = this.hitTest(e.clientX, e.clientY);
      if (hit) {
        this.showHoverPlace(hit.i);
      } else {
        this.clearHoverState();
        this.active = null;
      }
    },
    onUp(e) {
      if (!this.dragging) return;
      this.dragging = false;
      this.lastInteract = performance.now();
      if (this.moved < 6) {
        // treat as a tap
        const hit = this.hitTest(e.clientX, e.clientY);
        if (hit) {
          this.focusPlace(hit.i);
        } else {
          this.pinned = false;
          this.clearHoverState();
          this.active = null;
        }
      }
    },
    focusPlace(i) {
      const p = this.places[i];
      this.clearHoverState();
      this.active = p;
      this.pinned = true;
      this.lastInteract = performance.now();
      this.tween = [-p.coord[0], -p.coord[1]];
    },
  },
};
</script>

